{
  "resolution_strategies": [
    {
      "resolution_strategy_id": "RS1_conditional_suspected_customer_legitimation_before_risk_disclosure",
      "change_operations": [
        {
          "operation": "insert_before",
          "parameters": {
            "target_activity_label": "conduct risk disclosure",
            "new_activity_label": "legitimiation of suspected customer"
          }
        },
        {
          "operation": "modify_resource",
          "parameters": {
            "target_activity_label": "legitimiation of suspected customer",
            "new_resource": "money laundering officer"
          }
        },
        {
          "operation": "embed_activity_in_xor",
          "parameters": {
            "target_activity_label": "legitimiation of suspected customer",
            "condition": "data.customer_status == \"untrusted\"",
            "mode": "skip"
          }
        }
      ],
      "evaluation": {
        "compliance_degree": {
          "value": "full",
          "reason": "The missing activity \"legitimiation of suspected customer\" is added and assigned to the required resource \"money laundering officer\". The activity is also made conditional on the suspected or untrusted customer condition, supporting the related context requirement that this activity eventually follows when the customer is untrusted."
        },
        "resolution_context_consistency": {
          "value": "high",
          "reason": "The strategy does not modify the existing execution of customer data handling, investment advice, customer data update, or custody account conclusion. Placing the suspected-customer legitimation before risk disclosure preserves the existing order of risk disclosure and keeps the new control before later advisory and contract activities."
        },
        "change_cost": {
          "value": "medium",
          "reason": "The strategy requires three localized operations: inserting the missing activity, assigning its resource, and embedding it in a conditional XOR structure."
        },
        "structural_quality_impact": {
          "value": "low",
          "reason": "The added XOR introduces minor structural complexity, but it is localized and semantically appropriate because the suspected-customer legitimation should only execute for untrusted customers."
        },
        "change_location": {
          "value": "middle",
          "reason": "The change is applied after the initial customer onboarding branch and immediately before risk disclosure, which is in the middle part of the process."
        }
      }
    },
    {
      "resolution_strategy_id": "RS2_unconditional_suspected_customer_legitimation_before_risk_disclosure",
      "change_operations": [
        {
          "operation": "insert_before",
          "parameters": {
            "target_activity_label": "conduct risk disclosure",
            "new_activity_label": "legitimiation of suspected customer"
          }
        },
        {
          "operation": "modify_resource",
          "parameters": {
            "target_activity_label": "legitimiation of suspected customer",
            "new_resource": "money laundering officer"
          }
        }
      ],
      "evaluation": {
        "compliance_degree": {
          "value": "full",
          "reason": "The missing activity is inserted and assigned to the required resource, fully resolving the detected executed_by violation for \"legitimiation of suspected customer\"."
        },
        "resolution_context_consistency": {
          "value": "medium",
          "reason": "The strategy preserves the stated context requirements and ensures that the suspected-customer legitimation occurs before risk disclosure. However, it executes the activity for all customers, not only suspected or untrusted customers, which may unnecessarily alter compliant behavior."
        },
        "change_cost": {
          "value": "low",
          "reason": "Only two operations are required: one insertion and one resource assignment."
        },
        "structural_quality_impact": {
          "value": "low",
          "reason": "The process remains structurally simple because no additional branching or looping is introduced. The main drawback is behavioral over-inclusion rather than structural degradation."
        },
        "change_location": {
          "value": "middle",
          "reason": "The activity is inserted before \"conduct risk disclosure\", after the customer-status branch and before the advisory part of the process."
        }
      }
    },
    {
      "resolution_strategy_id": "RS3_local_new_customer_branch_insertion_after_identification",
      "change_operations": [
        {
          "operation": "insert_after",
          "parameters": {
            "target_activity_label": "conduct customer identification & legitimation",
            "new_activity_label": "legitimiation of suspected customer"
          }
        },
        {
          "operation": "modify_resource",
          "parameters": {
            "target_activity_label": "legitimiation of suspected customer",
            "new_resource": "money laundering officer"
          }
        },
        {
          "operation": "embed_activity_in_xor",
          "parameters": {
            "target_activity_label": "legitimiation of suspected customer",
            "condition": "data.customer_status == \"untrusted\"",
            "mode": "skip"
          }
        }
      ],
      "evaluation": {
        "compliance_degree": {
          "value": "full",
          "reason": "The missing activity is added and assigned to the required money laundering officer resource. This fully addresses the detected R5 violation."
        },
        "resolution_context_consistency": {
          "value": "medium",
          "reason": "The change is very local to the new-customer identification path and preserves the existing satisfied requirements. However, if the untrusted-customer condition can also occur for existing customers in the non-new branch, this placement may be less robust for the context requirement that untrusted status eventually leads to suspected-customer legitimation."
        },
        "change_cost": {
          "value": "medium",
          "reason": "Three operations are required, including a conditional embedding to avoid executing the activity for every new customer."
        },
        "structural_quality_impact": {
          "value": "low",
          "reason": "The structure remains clear and localized. The added XOR is semantically aligned with suspected-customer handling, but it slightly increases complexity inside the new-customer branch."
        },
        "change_location": {
          "value": "early",
          "reason": "The modification occurs in the initial customer identification and custody-account setup part of the process."
        }
      }
    },
    {
      "resolution_strategy_id": "RS4_refactor_combined_identification_activity",
      "change_operations": [
        {
          "operation": "rename",
          "parameters": {
            "target_activity_label": "conduct customer identification & legitimation",
            "new_activity_label": "legitimiation of suspected customer"
          }
        },
        {
          "operation": "modify_resource",
          "parameters": {
            "target_activity_label": "legitimiation of suspected customer",
            "new_resource": "money laundering officer"
          }
        },
        {
          "operation": "insert_before",
          "parameters": {
            "target_activity_label": "legitimiation of suspected customer",
            "new_activity_label": "conduct customer identification & legitimation"
          }
        },
        {
          "operation": "modify_resource",
          "parameters": {
            "target_activity_label": "conduct customer identification & legitimation",
            "new_resource": "customer advisor"
          }
        }
      ],
      "evaluation": {
        "compliance_degree": {
          "value": "full",
          "reason": "The previously combined identification and legitimation step is refactored into two explicit activities: customer identification by the customer advisor and suspected-customer legitimation by the money laundering officer."
        },
        "resolution_context_consistency": {
          "value": "medium",
          "reason": "The strategy preserves the required precedence before \"conclude custody account\" in the new-customer branch. However, it changes the meaning and resource allocation of an existing activity, which is more intrusive than simply adding the missing activity."
        },
        "change_cost": {
          "value": "high",
          "reason": "Four operations are required, including renaming an existing activity, changing its resource, inserting a replacement activity, and assigning the replacement resource."
        },
        "structural_quality_impact": {
          "value": "low",
          "reason": "The resulting sequence is structurally simple and arguably clearer because the two duties are separated. The impact is mainly semantic rather than structural."
        },
        "change_location": {
          "value": "early",
          "reason": "The changes occur in the early new-customer identification and legitimation part of the process."
        }
      }
    }
  ],
  "best_resolution_strategy_id": "RS1_conditional_suspected_customer_legitimation_before_risk_disclosure",
  "best_resolution_reason": "RS1 is recommended because it fully resolves the missing activity and resource assignment violation while preserving compliant behavior as much as possible. Unlike the unconditional insertion, it avoids executing suspected-customer legitimation for all customers. Unlike the branch-local insertion, it is placed after the customer-status branching and therefore better supports the context requirement that an untrusted customer eventually receives suspected-customer legitimation."
}
